import asyncio
from graph import agent
from state_schema import AgentState

async def run_research(company: str) -> str:
    initial_state = AgentState(
        messages=[
            {"role": "user", "content": f"Research {company}: recent news, financials, competitors."}
        ],
        steps=0,
        max_steps=20,
    )
    final_state = await agent.ainvoke(initial_state)
    # The last AI message without tool_calls is the final answer
    for msg in reversed(final_state["messages"]):
        if msg["role"] == "assistant" and not msg.get("tool_calls"):
            return msg["content"]
    return "Agent did not produce a final answer."

if __name__ == "__main__":
    result = asyncio.run(run_research("Stripe"))
    print(result)
